#include<bits/stdc++.h>
using namespace std;
int v[2025][2025];
void pan(int x1, int x2, int y1, int y2) {
	int ax = (x1 + x2) / 2;
	int ay = (y1 + y2) / 2;
	for (int i = x1; i <= x2; i++) {
		for (int j = y1; j <= y2; j++) {
			if (v[i][j] != 0) {
				if (i <= ax) {
					if (j <= ay) {
						v[ax][ay + 1] = 1;
						v[ax + 1][ay] = 1;
						v[ax + 1][ay + 1] = 1;
						cout << ax + 1 << " " << ay + 1 << ' ' << 1 << "\n";
					} else {
						v[ax][ay] = 2;
						v[ax+1][ay] = 2;
						v[ax + 1][ay + 1] = 2;
						cout << ax + 1 << " " << ay << ' ' << 2 << "\n";
					}
				} else {
					if (j <= ay) {
						v[ax][ay + 1] = 3;
						v[ax][ay] = 3;
						v[ax + 1][ay + 1] = 3;
						cout << ax << " " << ay + 1 << ' ' << 3 << "\n";
					} else {
						v[ax][ay] = 4;
						v[ax][ay + 1] = 4;
						v[ax + 1][ay] = 4;
						cout << ax << " " << ay << ' ' << 4 << "\n";
					}
				}
				return;
			}
		}
	}
}
void dfs(int x1, int x2, int y1, int y2) {
	if (x1 == x2 && y1 == y2) {
		return;
	}
	pan(x1, x2, y1, y2);
	int ax = (x1 + x2) / 2;
	int ay = (y1 + y2) / 2;
	dfs(x1, ax, y1, ay);
	dfs(ax + 1, x2, y1, ay);
	dfs(x1, ax, ay + 1, y2);
	dfs(ax + 1, x2, ay + 1, y2);
	return;

}
int main() {
	int k, x, y;
	cin >> k >> x >> y;
	v[x][y] = 1;
	dfs(1, 1 << k, 1, 1 << k);
	return 0;
}
